/// caller, so it gets a single caller slot re-borrowed inside its arm (see
/// [`dispatch_caller_local`]).
fn kernel_call_dispatch(
    proc_table: &mut [Proc; N_PROC_SLOTS],
    priv_table: &[Priv; NR_SYS_PROCS],
    caller_nr: ProcNr,
    msg: &mut Message,
